加载首页 加载更多 加载最新 接口路径 /api/v1/article/load /api/v1/article/loadmore /api/v1/article/loadnew 请求方式 POST POST POST 参数 ArticleHomeDto ArticleHomeDto ArticleHomeDto 响应结果 ResponseResult ResponseResult ResponseResult <p>ArticleHomeDto请求参数</p> <pre><code>package com.heima.model.article.dtos;

import lombok.Data;

import java.util.Date;

@Data
public class ArticleHomeDto {

    // 最大时间
    Date maxBehotTime;
    // 最小时间
    Date minBehotTime;
    // 分页size
    Integer size;
    // 频道ID
    String tag;
}
</code></pre>

